// app/page.tsx
import { revalidateTag, unstable_cache } from 'next/cache';
import { getAllProducts, syncProductsFromUpstream } from '@/lib/db';

const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ['admin-product-catalog'],
  {
    tags: ['products']
  }
);

async function syncLatestCatalog() {
  'use server';

  void syncProductsFromUpstream().then(() => {
    revalidateTag('products', 'max');
  });
}

export default async function Page() {
  const products = await getCachedProducts();

  return (
    <main style={{ fontFamily: 'Arial, sans-serif', padding: 32, maxWidth: 960, margin: '0 auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', gap: 24, marginBottom: 24 }}>
        <div>
          <p style={{ margin: 0, color: '#666', fontSize: 14, textTransform: 'uppercase', letterSpacing: '0.08em' }}>
            Admin
          </p>
          <h1 style={{ margin: '8px 0 12px', fontSize: 32 }}>Product Catalog</h1>
          <p style={{ margin: 0, color: '#444', lineHeight: 1.5, maxWidth: 640 }}>
            Browse the latest cached catalog snapshot. Use sync when ERP/PIM changes land—the refresh runs in the
            background so you can keep working while catalog views converge shortly after.
          </p>
        </div>

        <form action={syncLatestCatalog}>
          <button
            type="submit"
            style={{
              border: 'none',
              background: '#111827',
              color: '#fff',
              padding: '12px 18px',
              borderRadius: 10,
              cursor: 'pointer',
              fontWeight: 600
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </div>

      <section
        style={{
          border: '1px solid #e5e7eb',
          borderRadius: 16,
          overflow: 'hidden',
          boxShadow: '0 10px 30px rgba(0,0,0,0.04)'
        }}
      >
        <table style={{ width: '100%', borderCollapse: 'collapse', background: '#fff' }}>
          <thead style={{ background: '#f9fafb' }}>
            <tr>
              <th style={{ textAlign: 'left', padding: 16, fontSize: 13, color: '#6b7280' }}>SKU</th>
              <th style={{ textAlign: 'left', padding: 16, fontSize: 13, color: '#6b7280' }}>Product</th>
              <th style={{ textAlign: 'left', padding: 16, fontSize: 13, color: '#6b7280' }}>Price</th>
              <th style={{ textAlign: 'left', padding: 16, fontSize: 13, color: '#6b7280' }}>Inventory</th>
              <th style={{ textAlign: 'left', padding: 16, fontSize: 13, color: '#6b7280' }}>Availability</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id} style={{ borderTop: '1px solid #e5e7eb' }}>
                <td style={{ padding: 16, fontFamily: 'monospace' }}>{product.sku}</td>
                <td style={{ padding: 16, fontWeight: 600 }}>{product.name}</td>
                <td style={{ padding: 16 }}>${product.price.toFixed(2)}</td>
                <td style={{ padding: 16 }}>{product.inventory}</td>
                <td style={{ padding: 16 }}>
                  <span
                    style={{
                      display: 'inline-flex',
                      padding: '4px 10px',
                      borderRadius: 999,
                      background: product.available ? '#dcfce7' : '#fee2e2',
                      color: product.available ? '#166534' : '#991b1b',
                      fontSize: 13,
                      fontWeight: 600
                    }}
                  >
                    {product.available ? 'Available' : 'Unavailable'}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </section>
    </main>
  );
}


